function companyThemeKey(name) {
    return `company:${name}`;
}
function savedThemeKey(id) {
    return `saved:${id}`;
}
function buildThemeOptions(savedPalettes) {
    return [
        ...companyThemes.map((theme)=>({
                key: companyThemeKey(theme.name),
                name: theme.name,
                colors: [
                    ...theme.palette
                ]
            })),
        ...savedPalettes.filter((item)=>item.name.trim().length > 0).map((item)=>({
                key: savedThemeKey(item.id),
                name: item.name,
                colors: item.colors,
                deletable: true
            }))
    ];
}
function capitalizeWords(value) {
    return value.replace(/\b\w/g, (char)=>char.toUpperCase());
}
